sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    try {
        if (!gs.hasRole('x_146833_idpkiro.user')) {
            response.setStatus(403);
            response.setBody({ error: 'Access denied.' });
            return;
        }

        var metrics = {};

        // Deployment success rate (last 7 days)
        var totalDep = new GlideAggregate('change_request');
        totalDep.addQuery('type', 'standard');
        totalDep.addQuery('sys_created_on', '>=', gs.daysAgoStart(7));
        totalDep.addAggregate('COUNT');
        totalDep.query();
        var totalCount = totalDep.next() ? parseInt(totalDep.getAggregate('COUNT')) : 0;

        var successDep = new GlideAggregate('change_request');
        successDep.addQuery('type', 'standard');
        successDep.addQuery('sys_created_on', '>=', gs.daysAgoStart(7));
        successDep.addQuery('state', 3);
        successDep.addAggregate('COUNT');
        successDep.query();
        var successCount = successDep.next() ? parseInt(successDep.getAggregate('COUNT')) : 0;

        metrics.deployment_success_rate = totalCount > 0 ? Math.round((successCount / totalCount) * 1000) / 10 : null;
        metrics.total_deployments_7d = totalCount;

        // Active incidents
        var incAgg = new GlideAggregate('incident');
        incAgg.addQuery('active', true);
        incAgg.addAggregate('COUNT');
        incAgg.query();
        metrics.active_incidents = incAgg.next() ? parseInt(incAgg.getAggregate('COUNT')) : 0;

        // Service availability (placeholder)
        metrics.service_availability = 99.9;

        response.setStatus(200);
        response.setBody({ result: { metrics: metrics } });

    } catch (e) {
        gs.logError('IDP /observability/metrics error: ' + e.message, 'IDP-API');
        response.setStatus(500);
        response.setBody({ error: 'Internal server error.' });
    }
})(request, response);
